insert into public.official_wordbooks (id, title, major) values
  ('a1000000-0000-0000-0000-000000000001', '컴퓨터과학 핵심 어휘', '컴퓨터과학');
insert into public.official_words (wordbook_id, english, general_meaning, major_meaning, general_example, major_example) values
  ('a1000000-0000-0000-0000-000000000001', 'Algorithm', '방법, 절차', '문제를 해결하기 위한 단계적 연산 절차', 'There is a better algorithm for this task.', 'A sorting algorithm arranges data in a specific order efficiently.'),
  ('a1000000-0000-0000-0000-000000000001', 'Abstraction', '추상화', '복잡한 시스템의 세부 사항을 숨기고 핵심 개념만 노출하는 기법', 'Abstraction helps simplify complex ideas.', 'Abstraction in OOP allows programmers to focus on high-level logic without worrying about implementation details.'),
  ('a1000000-0000-0000-0000-000000000001', 'Compiler', '번역기', '고급 언어 소스코드를 기계어로 변환하는 프로그램', 'The compiler found an error in the code.', 'A compiler translates the entire source code into machine code before execution.'),
  ('a1000000-0000-0000-0000-000000000001', 'Recursion', '반복, 순환', '함수가 자기 자신을 호출하는 프로그래밍 기법', 'Recursion is a concept that refers back to itself.', 'Recursion is used to solve problems like tree traversal and factorial computation.'),
  ('a1000000-0000-0000-0000-000000000001', 'Polymorphism', '다형성', '동일한 인터페이스로 다양한 데이터 타입을 처리하는 OOP 특성', 'Polymorphism means taking many forms.', 'Polymorphism allows a single function to operate differently based on the object it acts upon.'),
  ('a1000000-0000-0000-0000-000000000001', 'Encapsulation', '캡슐화', '데이터와 메서드를 하나의 단위로 묶고 외부 접근을 제한하는 OOP 원칙', 'Encapsulation means wrapping things together.', 'Encapsulation protects an object''s internal state by restricting direct access from outside.'),
  ('a1000000-0000-0000-0000-000000000001', 'Inheritance', '상속', '부모 클래스의 속성과 메서드를 자식 클래스가 물려받는 OOP 개념', 'Children inherit traits from their parents.', 'Inheritance allows a subclass to reuse and extend the functionality of a parent class.'),
  ('a1000000-0000-0000-0000-000000000001', 'Data Structure', '자료 구조', '데이터를 효율적으로 저장·관리·접근하기 위한 구조적 방식', 'A data structure organizes information.', 'Choosing the right data structure significantly impacts algorithm performance.'),
  ('a1000000-0000-0000-0000-000000000001', 'Binary Tree', '이진 트리', '각 노드가 최대 두 개의 자식 노드를 갖는 트리 자료구조', 'A binary tree splits into two branches.', 'A binary search tree enables O(log n) search time by maintaining sorted order.'),
  ('a1000000-0000-0000-0000-000000000001', 'Stack', '쌓음, 무더기', '후입선출(LIFO) 방식으로 데이터를 관리하는 선형 자료구조', 'Stack the books on the shelf.', 'A stack is used in function call management and expression evaluation.'),
  ('a1000000-0000-0000-0000-000000000001', 'Queue', '줄, 대기열', '선입선출(FIFO) 방식으로 데이터를 관리하는 선형 자료구조', 'Please join the queue at the door.', 'A queue is used in scheduling processes and breadth-first search.'),
  ('a1000000-0000-0000-0000-000000000001', 'Hash Table', '해시 테이블', '키-값 쌍을 해시 함수로 색인화하여 O(1) 평균 탐색을 제공하는 자료구조', 'A hash table can store and retrieve data very quickly.', 'A hash table provides average O(1) time complexity for insert and lookup operations.'),
  ('a1000000-0000-0000-0000-000000000001', 'Graph', '그래프, 도표', '노드와 간선으로 구성된 비선형 자료구조로 관계를 표현함', 'The graph shows monthly sales.', 'A graph data structure models networks such as social connections or road maps.'),
  ('a1000000-0000-0000-0000-000000000001', 'Complexity', '복잡성', '알고리즘의 시간 또는 공간 자원 소모량을 나타내는 척도', 'The complexity of the problem is high.', 'Time complexity measures how an algorithm''s running time grows with input size.'),
  ('a1000000-0000-0000-0000-000000000001', 'Operating System', '운영 체제', '하드웨어 자원을 관리하고 응용 프로그램에 서비스를 제공하는 시스템 소프트웨어', 'The operating system manages all the programs on your computer.', 'An operating system manages CPU scheduling, memory allocation, and I/O operations.'),
  ('a1000000-0000-0000-0000-000000000001', 'Process', '과정, 절차', '실행 중인 프로그램의 인스턴스로 독립적인 메모리 공간을 가짐', 'The process of baking bread takes time.', 'A process is an independent unit of execution that the OS manages with its own memory space.'),
  ('a1000000-0000-0000-0000-000000000001', 'Thread', '실, 흐름', '프로세스 내에서 실행되는 경량 실행 단위로 메모리를 공유함', 'Pull the thread through the needle.', 'Threads within the same process share memory, enabling efficient concurrent execution.'),
  ('a1000000-0000-0000-0000-000000000001', 'Deadlock', '교착 상태', '두 개 이상의 프로세스가 서로의 자원을 기다리며 무한 대기하는 상태', 'The negotiation ended in a deadlock with no agreement reached.', 'Deadlock occurs when processes hold resources while waiting for others, causing a circular dependency.'),
  ('a1000000-0000-0000-0000-000000000001', 'Cache', '저장소, 캐시', '자주 사용하는 데이터를 빠른 접근 가능한 임시 저장소에 보관하는 기법', 'The browser cache stores temporary files.', 'Cache memory reduces average memory access time by storing frequently used data closer to the CPU.'),
  ('a1000000-0000-0000-0000-000000000001', 'Virtual Memory', '가상 메모리', '물리 메모리보다 큰 주소 공간을 제공하기 위해 디스크를 메모리처럼 사용하는 기법', 'Virtual memory lets your computer handle more tasks than the RAM alone allows.', 'Virtual memory allows processes to use more memory than physically available by paging to disk.'),
  ('a1000000-0000-0000-0000-000000000001', 'Interrupt', '방해, 중단', '하드웨어나 소프트웨어가 CPU에 즉각적인 처리를 요청하는 신호', 'Sorry to interrupt your work.', 'An interrupt signals the CPU to pause its current task and handle an urgent event.'),
  ('a1000000-0000-0000-0000-000000000001', 'Protocol', '규약, 프로토콜', '네트워크에서 데이터 교환을 위해 정의된 통신 규칙의 집합', 'Follow the safety protocol carefully.', 'HTTP is a protocol that defines how web clients and servers communicate over a network.'),
  ('a1000000-0000-0000-0000-000000000001', 'Encryption', '암호화', '데이터를 인가된 당사자만 읽을 수 있도록 변환하는 보안 기술', 'Encryption protects your private messages.', 'End-to-end encryption ensures that only the sender and recipient can read the transmitted data.'),
  ('a1000000-0000-0000-0000-000000000001', 'API', '응용 프로그램 인터페이스', '서로 다른 소프트웨어 컴포넌트가 통신하기 위한 인터페이스 명세', 'The weather app uses an API to fetch real-time data.', 'A RESTful API exposes server resources through HTTP endpoints for client applications to consume.'),
  ('a1000000-0000-0000-0000-000000000001', 'Database', '데이터베이스', '구조화된 데이터를 체계적으로 저장·관리하는 시스템', 'The company keeps a database of customers.', 'A relational database stores data in tables with defined relationships between them.'),
  ('a1000000-0000-0000-0000-000000000001', 'SQL', '구조적 질의 언어', '관계형 데이터베이스를 조작하기 위한 표준 질의 언어', 'You can use SQL to search and organize data stored in a database.', 'SQL SELECT statements retrieve specific records from a database based on given conditions.'),
  ('a1000000-0000-0000-0000-000000000001', 'Index', '색인, 인덱스', '데이터베이스 검색 속도를 높이기 위해 특정 컬럼에 생성하는 보조 자료구조', 'Check the index at the back of the book.', 'A database index speeds up query execution by allowing the engine to locate rows without a full scan.'),
  ('a1000000-0000-0000-0000-000000000001', 'Transaction', '거래, 트랜잭션', '데이터베이스에서 원자성을 보장하는 논리적 작업 단위', 'The bank transaction was completed.', 'A database transaction ensures ACID properties so that partial updates never corrupt data.'),
  ('a1000000-0000-0000-0000-000000000001', 'Normalization', '정규화', '데이터 중복을 최소화하고 무결성을 높이기 위해 테이블을 구조화하는 과정', 'Normalization of test scores makes it easier to compare results fairly.', 'Database normalization up to 3NF reduces redundancy and prevents update anomalies.'),
  ('a1000000-0000-0000-0000-000000000001', 'Machine Learning', '기계 학습', '데이터로부터 패턴을 학습하여 예측·분류하는 AI의 한 분야', 'Machine learning helps apps like music players suggest songs you might enjoy.', 'Machine learning models improve their performance as they are exposed to more training data.'),
  ('a1000000-0000-0000-0000-000000000001', 'Neural Network', '신경망', '인간 뇌의 뉴런 구조를 모방한 계층적 연산 모델', 'A neural network can recognize handwritten letters like a human brain.', 'A deep neural network learns hierarchical feature representations from raw input data.'),
  ('a1000000-0000-0000-0000-000000000001', 'Overfitting', '과적합', '모델이 훈련 데이터에 지나치게 맞춰져 새 데이터에 일반화되지 않는 현상', 'If you only study past exam questions, you risk overfitting and failing new ones.', 'Overfitting occurs when a model memorizes training data noise instead of learning generalizable patterns.'),
  ('a1000000-0000-0000-0000-000000000001', 'Version Control', '버전 관리', '소스코드의 변경 이력을 추적·관리하는 시스템', 'Version control lets you go back to an earlier draft of your document.', 'Git is a distributed version control system that tracks changes and supports branching workflows.'),
  ('a1000000-0000-0000-0000-000000000001', 'Refactoring', '리팩토링', '외부 동작을 변경하지 않고 코드의 내부 구조를 개선하는 작업', 'She spent the weekend refactoring her essay to make it clearer.', 'Refactoring improves code readability and maintainability without altering its observable behavior.'),
  ('a1000000-0000-0000-0000-000000000001', 'Design Pattern', '설계 패턴', '반복적으로 발생하는 소프트웨어 설계 문제에 대한 재사용 가능한 해결책', 'Following a design pattern for the room layout made decorating much easier.', 'The Singleton design pattern ensures a class has only one instance throughout the application.'),
  ('a1000000-0000-0000-0000-000000000001', 'Dependency Injection', '의존성 주입', '객체가 필요한 의존성을 외부에서 주입받는 설계 원칙', 'Dependency injection in cooking means adding ingredients at the right stage of the recipe.', 'Dependency injection decouples components by providing required objects from outside rather than creating them internally.'),
  ('a1000000-0000-0000-0000-000000000001', 'Concurrency', '동시성', '여러 작업이 동시에 진행되는 것처럼 처리되는 프로그래밍 개념', 'Concurrency means doing things at the same time.', 'Concurrency allows a program to manage multiple tasks by interleaving their execution on a single core.'),
  ('a1000000-0000-0000-0000-000000000001', 'Latency', '지연', '요청이 전송된 후 응답을 받기까지 걸리는 시간', 'High latency makes the video call choppy.', 'Network latency is the delay between sending a request and receiving a response over a network.'),
  ('a1000000-0000-0000-0000-000000000001', 'Throughput', '처리량', '단위 시간당 시스템이 처리하는 데이터 또는 작업의 양', 'The factory increased its throughput by adding an extra shift.', 'Server throughput measures the number of requests successfully handled per second.'),
  ('a1000000-0000-0000-0000-000000000001', 'Load Balancing', '부하 분산', '여러 서버에 트래픽을 고르게 분배하여 가용성과 성능을 높이는 기술', 'Good load balancing at the event meant no single entrance got too crowded.', 'Load balancing distributes incoming requests across multiple servers to prevent any single point of failure.'),
  ('a1000000-0000-0000-0000-000000000001', 'Container', '컨테이너', '애플리케이션과 그 의존성을 격리된 환경에 패키징하는 가상화 단위', 'Put the items in a container.', 'Docker containers package an application with all its dependencies for consistent deployment across environments.'),
  ('a1000000-0000-0000-0000-000000000001', 'Microservice', '마이크로서비스', '대형 애플리케이션을 독립 배포 가능한 소규모 서비스로 분리하는 아키텍처', 'The company restructured into microservices, each team handling one small product.', 'A microservice architecture decomposes an application into loosely coupled services that communicate via APIs.'),
  ('a1000000-0000-0000-0000-000000000001', 'Authentication', '인증', '사용자 또는 시스템의 신원을 확인하는 보안 절차', 'Authentication requires a valid ID.', 'Multi-factor authentication increases security by requiring two or more verification methods.'),
  ('a1000000-0000-0000-0000-000000000001', 'Authorization', '권한 부여', '인증된 주체가 특정 자원에 접근할 수 있는지 결정하는 보안 절차', 'You need authorization to enter this area.', 'Authorization determines what actions an authenticated user is permitted to perform on a resource.'),
  ('a1000000-0000-0000-0000-000000000001', 'Firewall', '방화벽', '미리 정의된 보안 규칙에 따라 네트워크 트래픽을 허용·차단하는 보안 장치', 'A firewall around the building prevented unauthorized access.', 'A firewall filters incoming and outgoing traffic based on security policies to block unauthorized access.'),
  ('a1000000-0000-0000-0000-000000000001', 'Bandwidth', '대역폭', '네트워크에서 단위 시간당 전송 가능한 최대 데이터량', 'This video requires high bandwidth.', 'Bandwidth determines the maximum data transfer rate of a network connection.'),
  ('a1000000-0000-0000-0000-000000000001', 'Debugging', '디버깅', '프로그램의 오류를 찾아 수정하는 과정', 'She spent hours debugging the issue.', 'Debugging involves systematically identifying, isolating, and fixing defects in source code.'),
  ('a1000000-0000-0000-0000-000000000001', 'Pointer', '포인터', '메모리 주소를 값으로 갖는 변수', 'The pointer on the map shows our location.', 'A pointer stores the memory address of another variable, enabling direct memory manipulation in C.'),
  ('a1000000-0000-0000-0000-000000000001', 'Garbage Collection', '가비지 컬렉션', '런타임이 더 이상 참조되지 않는 메모리를 자동으로 회수하는 메커니즘', 'Garbage collection in the city keeps the streets clean automatically.', 'Garbage collection frees developers from manual memory management by automatically reclaiming unused objects.'),
  ('a1000000-0000-0000-0000-000000000001', 'Bit', '비트', '컴퓨터에서 정보를 나타내는 가장 작은 단위(0 또는 1)', 'Every bit of information matters.', 'A bit is the fundamental unit of information in computing, representing a binary value of 0 or 1.');
insert into public.official_wordbooks (id, title, major) values
  ('a2000000-0000-0000-0000-000000000002', '경영학 핵심 어휘', '경영학');
insert into public.official_words (wordbook_id, english, general_meaning, major_meaning, general_example, major_example) values
  ('a2000000-0000-0000-0000-000000000002', 'Strategy', '전략, 계획', '조직의 장기적 목표 달성을 위해 자원을 배분하고 경쟁 우위를 확보하는 행동 방안', 'We need a strategy to win the game.', 'A corporate strategy defines how a firm will compete and achieve sustainable competitive advantage.'),
  ('a2000000-0000-0000-0000-000000000002', 'Stakeholder', '이해관계자', '기업의 활동에 영향을 주거나 받는 모든 개인 또는 집단', 'Every stakeholder in the project had a different opinion about the deadline.', 'Stakeholder analysis identifies all parties affected by a business decision, including employees, investors, and customers.'),
  ('a2000000-0000-0000-0000-000000000002', 'Supply Chain', '공급망', '원자재 조달부터 최종 소비자 전달까지의 전체 가치 흐름 네트워크', 'The supply chain for this product spans three different continents.', 'Supply chain disruptions during the pandemic caused global shortages of semiconductors.'),
  ('a2000000-0000-0000-0000-000000000002', 'Market Segmentation', '시장 세분화', '이질적인 전체 시장을 동질적 특성을 가진 소집단으로 나누는 과정', 'Market segmentation helped the team focus on the right customer groups.', 'Market segmentation allows companies to tailor products and messages to specific customer groups.'),
  ('a2000000-0000-0000-0000-000000000002', 'Competitive Advantage', '경쟁 우위', '경쟁자 대비 우월한 가치를 창출하여 지속적인 수익을 확보하는 능력', 'Her competitive advantage at the race was her speed off the starting line.', 'Apple''s ecosystem creates a competitive advantage by increasing switching costs for its customers.'),
  ('a2000000-0000-0000-0000-000000000002', 'Cash Flow', '현금 흐름', '일정 기간 동안 기업에 유입·유출되는 현금의 흐름', 'Managing your cash flow means knowing when money comes in and goes out.', 'Positive cash flow indicates that a company generates more cash than it spends, supporting operations.'),
  ('a2000000-0000-0000-0000-000000000002', 'Return on Investment', '투자수익률', '투자 비용 대비 창출된 이익의 비율을 나타내는 성과 지표', 'The ROI on this project is impressive.', 'ROI is calculated by dividing net profit by total investment cost and is used to evaluate project viability.'),
  ('a2000000-0000-0000-0000-000000000002', 'Leverage', '지렛대, 레버리지', '부채를 활용하여 자기자본 수익률을 높이는 재무 전략', 'Use the lever to lift the rock.', 'Financial leverage amplifies returns when asset returns exceed borrowing costs, but increases risk in downturns.'),
  ('a2000000-0000-0000-0000-000000000002', 'Liquidity', '유동성', '자산을 손실 없이 신속하게 현금으로 전환할 수 있는 능력', 'Water has high liquidity.', 'A firm''s liquidity ratio measures its ability to meet short-term obligations with current assets.'),
  ('a2000000-0000-0000-0000-000000000002', 'Depreciation', '감가상각', '유형자산의 가치가 시간 경과·사용에 따라 감소하는 것을 회계에 반영하는 절차', 'The car depreciation meant it was worth much less after three years.', 'Straight-line depreciation allocates the cost of an asset evenly over its useful life.'),
  ('a2000000-0000-0000-0000-000000000002', 'Equity', '공정성, 자본', '총자산에서 총부채를 차감한 주주의 몫으로서 기업의 순자산 가치', 'Equity means fairness for everyone.', 'Shareholders'' equity represents the residual interest in a firm''s assets after deducting all liabilities.'),
  ('a2000000-0000-0000-0000-000000000002', 'Liability', '책임, 부채', '기업이 과거 거래로 인해 미래에 자원을 이전해야 하는 현재 의무', 'He accepted liability for the accident.', 'Current liabilities are obligations due within one year, such as accounts payable and short-term loans.'),
  ('a2000000-0000-0000-0000-000000000002', 'Revenue', '수익', '기업이 주된 영업 활동에서 획득한 총수입', 'Their revenue increased this quarter.', 'Revenue is recognized when goods or services are delivered to customers under accrual accounting.'),
  ('a2000000-0000-0000-0000-000000000002', 'Profit Margin', '이익률', '매출액 대비 순이익의 비율로 수익성 효율을 나타내는 지표', 'A high profit margin means you keep more of each dollar you earn.', 'A high profit margin indicates that a company retains a large portion of each sales dollar as profit.'),
  ('a2000000-0000-0000-0000-000000000002', 'Balance Sheet', '재무상태표', '특정 시점의 자산, 부채, 자본을 나타내는 재무제표', 'The balance sheet showed the family''s total assets and debts at year end.', 'The balance sheet follows the accounting equation: Assets = Liabilities + Equity.'),
  ('a2000000-0000-0000-0000-000000000002', 'Income Statement', '손익계산서', '일정 기간의 수익과 비용을 대조하여 순이익을 산출하는 재무제표', 'The income statement revealed the business had earned a profit last quarter.', 'The income statement shows whether a company generated profit or incurred a loss during a reporting period.'),
  ('a2000000-0000-0000-0000-000000000002', 'Fixed Cost', '고정비', '생산량이나 판매량에 관계없이 일정하게 발생하는 비용', 'Rent is a fixed cost for the business.', 'Fixed costs such as rent and salaries remain constant regardless of output level.'),
  ('a2000000-0000-0000-0000-000000000002', 'Variable Cost', '변동비', '생산·판매량에 비례하여 변하는 비용', 'Your phone bill is a variable cost because it changes based on usage.', 'Raw materials are variable costs that increase directly with the quantity of goods produced.'),
  ('a2000000-0000-0000-0000-000000000002', 'Break-even Point', '손익분기점', '총수익과 총비용이 일치하여 이익도 손실도 발생하지 않는 생산·판매 수준', 'She needed to sell 100 tickets to reach the break-even point for the event.', 'Reaching the break-even point means total revenue equals total costs, with zero profit or loss.'),
  ('a2000000-0000-0000-0000-000000000002', 'Economies of Scale', '규모의 경제', '생산 규모 증가에 따라 단위당 비용이 감소하는 현상', 'Buying ingredients in bulk created economies of scale for the restaurant.', 'Economies of scale allow large manufacturers to reduce per-unit costs through mass production.'),
  ('a2000000-0000-0000-0000-000000000002', 'Diversification', '다각화', '리스크 분산을 위해 새로운 시장이나 제품으로 사업 영역을 확장하는 전략', 'Diversification of investments reduces risk.', 'A conglomerate pursues diversification by entering unrelated industries to spread business risk.'),
  ('a2000000-0000-0000-0000-000000000002', 'Brand Equity', '브랜드 자산', '브랜드 인지도와 이미지가 제품이나 서비스에 부가하는 경제적 가치', 'The brand equity of that logo made people trust the product immediately.', 'Strong brand equity allows companies to charge premium prices and command customer loyalty.'),
  ('a2000000-0000-0000-0000-000000000002', 'Market Share', '시장 점유율', '특정 시장에서 한 기업의 매출이 전체 시장 매출에서 차지하는 비율', 'Our market share grew after we launched the new product line.', 'Increasing market share is a key growth objective, especially in mature, low-growth industries.'),
  ('a2000000-0000-0000-0000-000000000002', 'Outsourcing', '외주, 아웃소싱', '비핵심 업무를 외부 전문 업체에 위탁하여 비용 효율을 높이는 전략', 'She decided to outsource the logo design to a freelance artist.', 'Many firms outsource IT support and manufacturing to reduce overhead and focus on core competencies.'),
  ('a2000000-0000-0000-0000-000000000002', 'Merger', '합병', '두 개 이상의 기업이 결합하여 단일 법인으로 통합되는 기업 결합 형태', 'The two clubs agreed to a merger.', 'The merger of two competitors can create synergies that reduce costs and expand market reach.'),
  ('a2000000-0000-0000-0000-000000000002', 'Acquisition', '인수', '한 기업이 다른 기업의 지배 지분을 매입하여 경영권을 획득하는 행위', 'The acquisition of rare stamps took years.', 'Amazon''s acquisition of Whole Foods allowed it to enter the physical grocery retail market.'),
  ('a2000000-0000-0000-0000-000000000002', 'Corporate Governance', '기업 지배구조', '기업을 통제·지휘하는 규칙, 관행, 프로세스의 체계', 'Good corporate governance ensures leaders are held accountable to the board.', 'Sound corporate governance ensures accountability and protects the interests of all stakeholders.'),
  ('a2000000-0000-0000-0000-000000000002', 'Leadership', '리더십', '목표 달성을 위해 조직 구성원에게 영향력을 발휘하고 방향을 제시하는 능력', 'Good leadership inspires the whole team.', 'Transformational leadership motivates employees by aligning personal goals with the organizational vision.'),
  ('a2000000-0000-0000-0000-000000000002', 'Motivation', '동기 부여', '개인이 목표 지향 행동을 시작하고 유지하게 하는 심리적 힘', 'His motivation to study is strong.', 'Maslow''s hierarchy of needs explains employee motivation by ranking human needs from basic to self-actualization.'),
  ('a2000000-0000-0000-0000-000000000002', 'Organizational Culture', '조직 문화', '조직 구성원이 공유하는 가치, 신념, 행동 규범의 총체', 'The friendly organizational culture made new employees feel welcome quickly.', 'A strong organizational culture aligned with strategy drives employee engagement and performance.'),
  ('a2000000-0000-0000-0000-000000000002', 'Human Resource Management', '인적자원관리', '조직의 목표 달성을 위해 인력을 채용·개발·평가·보상하는 경영 기능', 'Human resource management ensures staff are trained and fairly compensated.', 'Effective human resource management ensures the right people are in the right roles at the right time.'),
  ('a2000000-0000-0000-0000-000000000002', 'Benchmarking', '벤치마킹', '업계 최고의 관행이나 성과를 기준으로 자사의 성과를 비교·개선하는 과정', 'She used benchmarking to compare her study habits with top students.', 'Benchmarking against industry leaders helps companies identify performance gaps and adopt best practices.'),
  ('a2000000-0000-0000-0000-000000000002', 'Risk Management', '위험 관리', '조직 목표 달성을 위협하는 불확실성을 식별·평가·통제하는 체계적 과정', 'Good risk management means having a plan before problems arise.', 'Risk management involves identifying potential threats and implementing controls to minimize their impact.'),
  ('a2000000-0000-0000-0000-000000000002', 'Innovation', '혁신', '새로운 아이디어, 제품, 프로세스를 도입하여 가치를 창출하는 활동', 'Innovation drives progress in society.', 'Disruptive innovation introduces simpler, cheaper solutions that eventually displace established market leaders.'),
  ('a2000000-0000-0000-0000-000000000002', 'Entrepreneurship', '기업가 정신', '불확실한 환경에서 기회를 포착하고 자원을 결합하여 새로운 가치를 창출하는 역량', 'Entrepreneurship requires courage to start something new despite uncertainty.', 'Entrepreneurship drives economic growth by introducing new products and creating employment opportunities.'),
  ('a2000000-0000-0000-0000-000000000002', 'Marketing Mix', '마케팅 믹스', '목표 시장에서 마케팅 목표를 달성하기 위한 4P(제품·가격·유통·촉진)의 조합', 'The marketing mix of price, product, place, and promotion shaped the campaign.', 'The marketing mix helps firms craft a coordinated strategy across product, price, place, and promotion.'),
  ('a2000000-0000-0000-0000-000000000002', 'Consumer Behavior', '소비자 행동', '소비자가 제품을 탐색·구매·사용·처분하는 과정과 그에 영향을 미치는 요인', 'Consumer behavior research revealed people prefer smaller packaging for snacks.', 'Understanding consumer behavior enables marketers to predict purchase decisions and design effective campaigns.'),
  ('a2000000-0000-0000-0000-000000000002', 'Value Chain', '가치 사슬', '기업이 제품이나 서비스에 가치를 추가하는 일련의 활동 체계', 'Each step in the value chain adds something useful to the final product.', 'Porter''s value chain model analyzes primary and support activities to identify sources of competitive advantage.'),
  ('a2000000-0000-0000-0000-000000000002', 'Porter''s Five Forces', '포터의 5가지 경쟁요인', '산업 내 경쟁 강도를 결정하는 다섯 가지 구조적 요인을 분석하는 프레임워크', 'Porter''s Five Forces analysis helped identify the biggest threats in the industry.', 'Porter''s Five Forces analyzes rivalry, supplier power, buyer power, substitutes, and new entrants.'),
  ('a2000000-0000-0000-0000-000000000002', 'SWOT Analysis', 'SWOT 분석', '강점·약점·기회·위협을 통해 전략적 상황을 진단하는 프레임워크', 'A SWOT analysis helped the team understand their strengths and weaknesses.', 'SWOT analysis helps companies leverage strengths and opportunities while mitigating weaknesses and threats.'),
  ('a2000000-0000-0000-0000-000000000002', 'KPI', '핵심 성과 지표', '조직의 전략 목표 달성 수준을 측정하기 위한 정량적 지표', 'Setting KPIs helped the team track their weekly progress clearly.', 'Setting clear KPIs enables management to track progress toward strategic goals objectively.'),
  ('a2000000-0000-0000-0000-000000000002', 'Fiscal Policy', '재정 정책', '정부가 조세와 지출을 조정하여 경기를 안정시키는 경제 정책', 'The government''s fiscal policy cut taxes to encourage more spending.', 'Expansionary fiscal policy increases government spending to stimulate economic growth during a recession.'),
  ('a2000000-0000-0000-0000-000000000002', 'Monetary Policy', '통화 정책', '중앙은행이 금리와 통화량을 조절하여 물가와 고용을 안정시키는 정책', 'The central bank used monetary policy to keep prices stable.', 'The central bank tightened monetary policy by raising interest rates to curb inflation.'),
  ('a2000000-0000-0000-0000-000000000002', 'Inflation', '인플레이션', '물가 수준이 지속적으로 상승하여 화폐의 구매력이 하락하는 현상', 'Inflation makes groceries more expensive.', 'Demand-pull inflation occurs when aggregate demand exceeds aggregate supply in the economy.'),
  ('a2000000-0000-0000-0000-000000000002', 'Globalization', '세계화', '국가 간 무역·투자·문화 교류가 확대되어 세계 경제가 통합되는 과정', 'Globalization means you can buy products made on the other side of the world.', 'Globalization allows firms to access cheaper labor markets and a broader customer base worldwide.'),
  ('a2000000-0000-0000-0000-000000000002', 'Corporate Social Responsibility', '기업의 사회적 책임', '기업이 이윤 추구를 넘어 사회·환경적 영향에 책임을 지는 경영 철학', 'Corporate social responsibility led the company to reduce its plastic waste.', 'CSR initiatives improve brand reputation and attract socially conscious investors and consumers.'),
  ('a2000000-0000-0000-0000-000000000002', 'Dividend', '배당금', '기업이 주주에게 이익의 일부를 현금이나 주식으로 분배하는 것', 'Shareholders received a dividend payment at the end of the year.', 'Companies with stable cash flows often pay regular dividends to reward long-term shareholders.'),
  ('a2000000-0000-0000-0000-000000000002', 'Venture Capital', '벤처 캐피털', '고위험·고성장 잠재력을 가진 초기 스타트업에 투자하는 민간 자본', 'Venture capital funding helped the young startup hire its first engineers.', 'Venture capital firms provide funding and mentorship to early-stage startups in exchange for equity.'),
  ('a2000000-0000-0000-0000-000000000002', 'Audit', '감사', '재무제표나 내부 통제의 정확성과 적법성을 독립적으로 검증하는 절차', 'The audit of their expense reports found several billing errors.', 'An external audit provides shareholders with an independent opinion on the accuracy of financial statements.'),
  ('a2000000-0000-0000-0000-000000000002', 'Franchise', '프랜차이즈', '본사가 가맹점에 브랜드·시스템·지원을 제공하고 대가를 받는 사업 모델', 'He opened a pizza franchise downtown.', 'A franchise model allows rapid market expansion while transferring operational risk to individual franchisees.');
insert into public.official_wordbooks (id, title, major) values
  ('a3000000-0000-0000-0000-000000000003', '역사학 핵심 어휘', '역사학');
insert into public.official_words (wordbook_id, english, general_meaning, major_meaning, general_example, major_example) values
  ('a3000000-0000-0000-0000-000000000003', 'Historiography', '역사 서술', '역사를 연구·기술하는 방법론과 그 발전 과정에 대한 학문적 연구', 'Her historiography of the event was praised for its thorough research.', 'Historiography examines how historical interpretations have changed over time and across scholarly traditions.'),
  ('a3000000-0000-0000-0000-000000000003', 'Primary Source', '1차 사료', '역사적 사건을 직접 기록한 원본 자료(일기, 편지, 공문서 등)', 'The journalist relied on primary sources rather than secondhand reports.', 'Historians rely on primary sources such as diaries and official documents to reconstruct past events accurately.'),
  ('a3000000-0000-0000-0000-000000000003', 'Secondary Source', '2차 자료', '1차 사료를 분석·해석한 후대의 학술 저작', 'The student used secondary sources to support the argument in her essay.', 'Secondary sources synthesize primary evidence to provide broader context and scholarly interpretation.'),
  ('a3000000-0000-0000-0000-000000000003', 'Chronology', '연대기', '사건을 시간 순서에 따라 배열한 역사 서술 방식', 'The timeline shows the chronology of events.', 'Establishing an accurate chronology is essential before analyzing the causes and effects of historical events.'),
  ('a3000000-0000-0000-0000-000000000003', 'Imperialism', '제국주의', '강대국이 정치·경제·군사적 수단으로 약소국을 지배하고 영토를 확장하는 정책', 'Imperialism often leads one country to dominate and exploit another.', 'European imperialism in the 19th century led to the colonization of large parts of Africa and Asia.'),
  ('a3000000-0000-0000-0000-000000000003', 'Colonialism', '식민주의', '한 나라가 다른 지역을 점령하여 경제적으로 착취하고 정치적으로 지배하는 체제', 'Colonialism left a lasting mark on the culture and language of many nations.', 'Colonialism left lasting economic and cultural impacts on formerly colonized nations in Africa and Asia.'),
  ('a3000000-0000-0000-0000-000000000003', 'Revolution', '혁명', '기존의 정치·사회·경제 체제를 근본적으로 전복하는 급격한 변혁', 'The industrial revolution changed society.', 'The French Revolution dismantled the absolute monarchy and laid the groundwork for modern democracy.'),
  ('a3000000-0000-0000-0000-000000000003', 'Nationalism', '민족주의', '민족적 정체성을 강조하고 민족 국가의 형성·독립을 추구하는 정치적 이념', 'Nationalism can unite a country but sometimes leads to conflict with others.', 'Nationalism in the 19th century fueled independence movements and the unification of Germany and Italy.'),
  ('a3000000-0000-0000-0000-000000000003', 'Feudalism', '봉건제', '중세 유럽에서 토지를 매개로 한 주종 관계에 기반한 사회·정치 체제', 'The feudalism of the village meant the landlord controlled all the farmland.', 'Feudalism structured medieval society into lords, vassals, and serfs bound by obligations of land and service.'),
  ('a3000000-0000-0000-0000-000000000003', 'Renaissance', '르네상스', '14~17세기 유럽에서 고대 그리스·로마 문화를 재발견한 문예 부흥 운동', 'The neighborhood saw a renaissance after new cafes and galleries opened.', 'The Renaissance fostered humanism and scientific inquiry, breaking from the medieval theological worldview.'),
  ('a3000000-0000-0000-0000-000000000003', 'Reformation', '종교 개혁', '16세기 유럽에서 가톨릭교회의 권위에 도전하여 개신교를 탄생시킨 종교 운동', 'The reformation of the school''s rules made students feel more respected.', 'The Protestant Reformation, led by Martin Luther, fragmented Western Christianity and reshaped European politics.'),
  ('a3000000-0000-0000-0000-000000000003', 'Enlightenment', '계몽주의', '17~18세기 유럽에서 이성과 과학을 중시하며 전통 권위에 도전한 지적 운동', 'Reading widely led to an enlightenment about how the world really works.', 'The Enlightenment promoted reason, individual rights, and secularism, influencing the American and French revolutions.'),
  ('a3000000-0000-0000-0000-000000000003', 'Industrial Revolution', '산업혁명', '18~19세기 영국에서 시작된 기계제 대공업으로의 생산 방식 전환과 사회 변혁', 'The industrial revolution changed how goods were made and how people lived.', 'The Industrial Revolution transformed agrarian societies into industrial economies, urbanizing populations rapidly.'),
  ('a3000000-0000-0000-0000-000000000003', 'Cold War', '냉전', '2차 세계대전 이후 미국과 소련이 직접 충돌 없이 이념·군비 경쟁을 벌인 국제 갈등 구조', 'There was a cold war of silence between the two neighbors for years.', 'The Cold War shaped global politics from 1947 to 1991 through proxy wars, the arms race, and ideological rivalry.'),
  ('a3000000-0000-0000-0000-000000000003', 'Totalitarianism', '전체주의', '국가 권력이 개인의 모든 생활 영역을 통제하는 극단적 권위주의 정치 체제', 'Totalitarianism leaves no room for individual freedom or dissent.', 'Totalitarianism in Nazi Germany and Stalinist USSR relied on propaganda, secret police, and mass terror.'),
  ('a3000000-0000-0000-0000-000000000003', 'Democracy', '민주주의', '국민이 주권을 가지고 대표자를 통해 정치에 참여하는 정치 체제', 'Democracy gives citizens the right to vote.', 'Athenian democracy in the 5th century BCE is considered the earliest example of citizen self-governance.'),
  ('a3000000-0000-0000-0000-000000000003', 'Diplomacy', '외교', '국가 간 협상과 교섭을 통해 국제 관계를 평화적으로 관리하는 활동', 'Diplomacy is preferable to conflict.', 'The Congress of Vienna (1815) demonstrated multilateral diplomacy to restore European order after Napoleonic wars.'),
  ('a3000000-0000-0000-0000-000000000003', 'Hegemony', '헤게모니', '한 국가·집단이 다른 국가·집단에 대해 갖는 정치·문화적 지배력', 'One team''s hegemony in the league made competition less exciting.', 'U.S. hegemony after World War II shaped international institutions such as the IMF and the United Nations.'),
  ('a3000000-0000-0000-0000-000000000003', 'Propaganda', '선전', '특정 정치적 목적을 위해 대중의 여론을 조작하는 정보 활동', 'Wartime propaganda was used on posters.', 'The Nazi regime used propaganda through film, radio, and rallies to manipulate public opinion and consolidate power.'),
  ('a3000000-0000-0000-0000-000000000003', 'Alliance', '동맹', '공동의 목표나 이익을 위해 국가 또는 집단이 맺는 공식 협력 관계', 'The two countries formed an alliance.', 'The Triple Alliance and Triple Entente formed rival alliance systems that escalated World War I.'),
  ('a3000000-0000-0000-0000-000000000003', 'Treaty', '조약', '국가 간의 권리·의무를 규정하는 공식적인 국제 법적 합의', 'The treaty ended the war officially.', 'The Treaty of Versailles imposed heavy reparations on Germany, contributing to the rise of National Socialism.'),
  ('a3000000-0000-0000-0000-000000000003', 'Sovereignty', '주권', '국가가 자국 영토 내에서 최고의 통치 권위를 갖는 원칙', 'Every person has sovereignty over their own personal decisions.', 'The Peace of Westphalia (1648) established the principle of state sovereignty in international relations.'),
  ('a3000000-0000-0000-0000-000000000003', 'Genocide', '집단학살', '특정 민족·종교·집단을 체계적으로 말살하려는 의도적인 대량 학살 행위', 'Genocide is one of the most severe crimes against humanity.', 'The Holocaust was a state-sponsored genocide in which Nazi Germany systematically murdered six million Jews.'),
  ('a3000000-0000-0000-0000-000000000003', 'Manifest Destiny', '명백한 운명', '미국이 북미 대륙 전체로 영토를 확장하는 것이 신의 뜻이라는 19세기 팽창주의 신념', 'He felt it was his manifest destiny to lead the project from start to finish.', 'Manifest Destiny justified westward expansion and the displacement of Native American populations in the 19th century.'),
  ('a3000000-0000-0000-0000-000000000003', 'Abolition', '폐지', '특히 노예제도를 법적·도덕적으로 금지하고 철폐하는 운동', 'The abolition of unfair laws was demanded.', 'The abolitionist movement in the U.S. campaigned against slavery and contributed to the Civil War.'),
  ('a3000000-0000-0000-0000-000000000003', 'Suffrage', '선거권, 참정권', '선거에 참여하여 투표할 수 있는 법적 권리', 'Universal suffrage means every adult citizen can vote in elections.', 'The suffrage movement secured voting rights for women in the United States with the 19th Amendment in 1920.'),
  ('a3000000-0000-0000-0000-000000000003', 'Decolonization', '탈식민화', '식민 지배에서 벗어나 독립 국가를 수립하는 정치적 과정', 'Decolonization of the mind means freeing yourself from imposed beliefs.', 'Decolonization after World War II led to the independence of dozens of African and Asian nations.'),
  ('a3000000-0000-0000-0000-000000000003', 'Civil Rights Movement', '민권 운동', '인종 차별 철폐와 법적 평등을 요구한 미국의 사회 운동(1950~60년대)', 'The civil rights movement demanded equal treatment for all citizens.', 'The Civil Rights Movement, led by figures like Martin Luther King Jr., ended legal segregation in the United States.'),
  ('a3000000-0000-0000-0000-000000000003', 'Partition', '분할', '국가나 지역을 정치적·민족적 경계에 따라 나누는 행위', 'The wall marked the partition of the city.', 'The partition of India in 1947 created the independent states of India and Pakistan, causing mass migration and violence.'),
  ('a3000000-0000-0000-0000-000000000003', 'Archaeology', '고고학', '유물·유적의 발굴과 분석을 통해 과거 인류의 문화와 생활을 연구하는 학문', 'Archaeology uncovered ancient tools buried beneath the city streets.', 'Archaeological excavations at Pompeii revealed detailed evidence of daily life in ancient Rome.'),
  ('a3000000-0000-0000-0000-000000000003', 'Artifact', '유물', '과거 인류가 만들고 사용한 물질적 증거로 역사 연구의 핵심 자료', 'The artifact was found in a cave.', 'Artifacts such as pottery and tools provide material evidence for reconstructing prehistoric cultures.'),
  ('a3000000-0000-0000-0000-000000000003', 'Oral History', '구술 역사', '문헌 기록이 없는 역사를 당사자나 목격자의 증언을 통해 수집·보존하는 방법', 'Oral history from elders preserved stories that were never written down.', 'Oral history interviews capture personal experiences and perspectives absent from official written records.'),
  ('a3000000-0000-0000-0000-000000000003', 'Paradigm Shift', '패러다임 전환', '지배적인 사고 체계나 이론이 근본적으로 교체되는 역사적·학문적 변혁', 'The invention of the internet was a paradigm shift in how people communicate.', 'Copernicus''s heliocentric model triggered a paradigm shift in how Europeans understood the cosmos.'),
  ('a3000000-0000-0000-0000-000000000003', 'Periodization', '시대 구분', '역사를 특정 기준에 따라 시기별로 나누는 방식', 'Periodization of a student''s progress helped teachers plan lessons.', 'Periodization such as ancient, medieval, and modern helps organize history but reflects particular cultural perspectives.'),
  ('a3000000-0000-0000-0000-000000000003', 'Revisionism', '수정주의', '기존의 역사적 해석을 비판하고 새로운 증거와 관점으로 재평가하는 학문적 경향', 'Revisionism in the debate challenged the commonly accepted version of events.', 'Historical revisionism challenges mainstream narratives by incorporating marginalized voices and new archival evidence.'),
  ('a3000000-0000-0000-0000-000000000003', 'Diaspora', '디아스포라', '본국을 떠나 해외 각지에 흩어져 정착한 민족 집단과 그 현상', 'The diaspora community maintained their traditions even far from their homeland.', 'The African diaspora, caused by the transatlantic slave trade, profoundly shaped cultures across the Americas.'),
  ('a3000000-0000-0000-0000-000000000003', 'Mercantilism', '중상주의', '수출 극대화·수입 최소화로 국부를 축적하려 한 16~18세기 유럽의 경제 이론', 'Mercantilism favored exports over imports to build national wealth.', 'Mercantilism drove colonial expansion as European powers sought raw materials and captive markets overseas.'),
  ('a3000000-0000-0000-0000-000000000003', 'Social Contract', '사회 계약', '개인이 자연 상태를 벗어나 사회를 형성하기 위해 권리 일부를 국가에 위임한다는 정치 이론', 'Living in a community involves a social contract to respect shared rules.', 'Rousseau''s social contract theory argued that legitimate government derives its authority from the consent of the governed.'),
  ('a3000000-0000-0000-0000-000000000003', 'Feudal Lord', '봉건 영주', '봉건제 하에서 토지를 소유하고 신하에게 봉토를 나누어 준 지배 계층', 'The feudal lord controlled all the land and collected taxes from farmers.', 'Feudal lords granted land to vassals in exchange for military service and political loyalty.'),
  ('a3000000-0000-0000-0000-000000000003', 'Crusade', '십자군', '11~13세기 기독교 국가들이 이슬람 세력으로부터 성지 예루살렘 탈환을 목표로 벌인 군사 원정', 'He launched a crusade to clean up the polluted river in his community.', 'The Crusades intensified cultural exchange between Europe and the Islamic world while causing widespread violence.'),
  ('a3000000-0000-0000-0000-000000000003', 'Emancipation', '해방', '법적·사회적 구속에서 벗어나 자유와 권리를 획득하는 과정', 'She fought for the emancipation of women.', 'Lincoln''s Emancipation Proclamation of 1863 declared enslaved people in Confederate states to be free.'),
  ('a3000000-0000-0000-0000-000000000003', 'Industrialization', '산업화', '경제 구조가 농업 중심에서 제조업·기계 생산 중심으로 전환되는 사회 변화 과정', 'Industrialization of the town brought jobs but also pollution.', 'Rapid industrialization in 19th-century Britain created urban slums and fueled the labor movement.'),
  ('a3000000-0000-0000-0000-000000000003', 'Secularism', '세속주의', '종교와 국가를 분리하고 공적 영역에서 종교의 영향력을 배제하는 원칙', 'Secularism in government means laws are made without religious influence.', 'The Enlightenment promoted secularism, shifting authority from the Church to reason and science.'),
  ('a3000000-0000-0000-0000-000000000003', 'Assimilation', '동화', '소수 집단이 지배 문화의 언어·관습·가치를 받아들이는 문화적 흡수 과정', 'Assimilation into a new culture takes time.', 'Colonial assimilation policies suppressed indigenous languages and cultures to impose European norms.'),
  ('a3000000-0000-0000-0000-000000000003', 'Bourgeoisie', '부르주아지', '마르크스 이론에서 생산수단을 소유한 자본가 계급', 'The bourgeoisie in the story enjoyed luxury while workers struggled.', 'Marx argued that the bourgeoisie exploited the proletariat by appropriating surplus value from their labor.'),
  ('a3000000-0000-0000-0000-000000000003', 'Proletariat', '프롤레타리아트', '마르크스 이론에서 생산수단 없이 노동력을 판매하는 노동자 계급', 'The proletariat marched to demand better pay and working conditions.', 'Marx predicted that the proletariat would eventually overthrow the bourgeoisie to establish a classless society.'),
  ('a3000000-0000-0000-0000-000000000003', 'Zeitgeist', '시대정신', '특정 시대와 사회를 지배하는 지적·문화적 분위기와 사상의 총체', 'The Zeitgeist of the decade was captured perfectly by that famous film.', 'The Zeitgeist of the 1960s was defined by counterculture, civil rights activism, and anti-war protest.'),
  ('a3000000-0000-0000-0000-000000000003', 'Annales School', '아날학파', '20세기 프랑스에서 장기 구조와 사회·경제 요인을 강조한 역사학의 주요 사조', 'The Annales School approach focuses on everyday life rather than famous events.', 'The Annales School shifted historical focus from political events to long-term social and geographic structures.'),
  ('a3000000-0000-0000-0000-000000000003', 'Mandate', '위임 통치', '국제연맹이 특정 국가에 부여한 영토 관리 권한', 'The government has a mandate to reform.', 'After World War I, the League of Nations assigned mandates over former Ottoman territories to Britain and France.'),
  ('a3000000-0000-0000-0000-000000000003', 'Reparations', '배상', '전쟁이나 부당 행위로 인한 피해를 금전·물자로 보상하는 것', 'The company paid reparations to communities affected by the oil spill.', 'The reparations imposed on Germany by the Treaty of Versailles contributed to economic instability and political radicalization.');
