-- ----------------------------------------------------------------
-- 0. 기존 시드 데이터 초기화 (재실행 시 중복 방지)
-- ----------------------------------------------------------------
delete from public.official_words
where wordbook_id in (
  select id from public.official_wordbooks
  where major in ('컴퓨터과학', '경영학', '역사학')
);
delete from public.official_wordbooks
where major in ('컴퓨터과학', '경영학', '역사학');

